import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [filteredVehicles, setFilteredVehicles] = useState([]);
  const [selectedType, setSelectedType] = useState("all");
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        setLoading(true);
        const res = await axios.get("http://localhost:8070/api/vehicles");

        const available = (res.data || []).filter(
          (v) => (v.status || "").toLowerCase() === "available"
        );

        setVehicles(available);
        setFilteredVehicles(available);

        const uniqueTypes = [
          ...new Set(available.map((v) => v.type).filter(Boolean)),
        ];
        setTypes(uniqueTypes);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();
  }, []);

  const handleFilterChange = (e) => {
    const value = e.target.value;
    setSelectedType(value);

    if (value === "all") {
      setFilteredVehicles(vehicles);
    } else {
      setFilteredVehicles(vehicles.filter((v) => v.type === value));
    }
  };

  const stats = useMemo(() => {
    const total = vehicles.length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);
    const avgPrice = total ? totalValue / total : 0;

    return {
      total,
      types: types.length,
      totalValue,
      avgPrice,
    };
  }, [vehicles, types]);

  const featuredVehicles = filteredVehicles.slice(0, 3);

  return (
    <div style={{ backgroundColor: "var(--bg)" }}>
      {/* HERO SECTION */}
      <div style={{
        background: "linear-gradient(135deg, var(--primary) 0%, rgba(26, 71, 42, 0.9) 100%)",
        color: "white",
        padding: "120px 20px",
        textAlign: "center",
        marginBottom: 80,
        position: "relative",
        overflow: "hidden"
      }}>
        {/* Decorative background elements */}
        <div style={{
          position: "absolute",
          top: "-50%",
          right: "-10%",
          width: "500px",
          height: "500px",
          borderRadius: "50%",
          backgroundColor: "rgba(255, 255, 255, 0.05)",
          filter: "blur(40px)"
        }} />
        <div style={{
          position: "absolute",
          bottom: "-30%",
          left: "-5%",
          width: "400px",
          height: "400px",
          borderRadius: "50%",
          backgroundColor: "rgba(255, 255, 255, 0.03)",
          filter: "blur(40px)"
        }} />

        <div style={{ maxWidth: 900, margin: "0 auto", position: "relative", zIndex: 1 }}>
          <div style={{
            fontSize: "56px",
            fontWeight: 800,
            letterSpacing: "-1px",
            marginBottom: 20,
            lineHeight: 1.2,
            textShadow: "0 2px 10px rgba(0, 0, 0, 0.2)"
          }}>
            Premium Vehicles, 
            <br />
            Extraordinary Experience
          </div>
          <div style={{
            fontSize: "18px",
            fontWeight: 300,
            opacity: 0.95,
            marginBottom: 40,
            lineHeight: 1.6,
            letterSpacing: "0.3px"
          }}>
            Discover our curated collection of luxury and premium vehicles. 
            <br />
            Professional service, competitive pricing, exceptional value.
          </div>
          <div style={{ display: "flex", gap: 16, justifyContent: "center", flexWrap: "wrap" }}>
            <button onClick={() => navigate("/vehicles")} style={{
              backgroundColor: "white",
              color: "var(--primary)",
              fontWeight: 700,
              padding: "14px 32px",
              fontSize: "15px",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              transition: "all 0.3s ease",
              letterSpacing: "0.3px",
              boxShadow: "0 8px 24px rgba(0, 0, 0, 0.2)"
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-3px)";
              e.currentTarget.style.boxShadow = "0 12px 32px rgba(0, 0, 0, 0.3)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow = "0 8px 24px rgba(0, 0, 0, 0.2)";
            }}>
              Browse Complete Inventory
            </button>
            <button onClick={() => navigate("/book-appointment")} style={{
              backgroundColor: "rgba(255,255,255,0.15)",
              color: "white",
              border: "2px solid rgba(255, 255, 255, 0.4)",
              fontWeight: 700,
              padding: "14px 32px",
              fontSize: "15px",
              borderRadius: "8px",
              cursor: "pointer",
              transition: "all 0.3s ease",
              letterSpacing: "0.3px",
              backdropFilter: "blur(10px)"
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = "rgba(255,255,255,0.25)";
              e.currentTarget.style.borderColor = "rgba(255, 255, 255, 0.6)";
              e.currentTarget.style.transform = "translateY(-3px)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = "rgba(255,255,255,0.15)";
              e.currentTarget.style.borderColor = "rgba(255, 255, 255, 0.4)";
              e.currentTarget.style.transform = "translateY(0)";
            }}>
              Schedule Test Drive
            </button>
          </div>
        </div>
      </div>

      {/* STATS SECTION */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 80 }}>
        <div style={{ marginBottom: 48 }}>
          <h2 style={{
            fontSize: "32px",
            fontWeight: 800,
            color: "var(--text)",
            margin: 0,
            letterSpacing: "-0.5px"
          }}>
            Why Choose Leaf Lanka
          </h2>
          <p style={{
            fontSize: "16px",
            color: "var(--text-muted)",
            margin: "12px 0 0 0",
            fontWeight: 300
          }}>
            Leading the automotive market with excellence and integrity
          </p>
        </div>
        <div style={{ 
          display: "grid", 
          gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", 
          gap: 24 
        }}>
          <StatCard 
            number={loading ? "—" : stats.total} 
            label="Available Vehicles" 
            description="In our inventory"
            icon="🚗"
          />
          <StatCard 
            number={loading ? "—" : stats.types} 
            label="Vehicle Types" 
            description="Diverse selection"
            icon="🏆"
          />
          <StatCard 
            number={loading ? "—" : `LKR ${(stats.totalValue / 1000000).toFixed(1)}M`} 
            label="Total Value" 
            description="Combined inventory"
            icon="💎"
          />
          <StatCard 
            number={loading ? "—" : `LKR ${Math.round(stats.avgPrice / 100000) * 100000 / 100000}`} 
            label="Avg. Price" 
            description="Market rate"
            icon="💰"
          />
        </div>
      </div>

      {/* FEATURED VEHICLES */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 80 }}>
        <div style={{ marginBottom: 48 }}>
          <h2 style={{
            fontSize: "32px",
            fontWeight: 800,
            color: "var(--text)",
            margin: 0,
            letterSpacing: "-0.5px"
          }}>
            Featured Vehicles
          </h2>
          <p style={{
            fontSize: "16px",
