      {/* FILTER AND BROWSE SECTION */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 80 }}>
        <div style={{ marginBottom: 48 }}>
          <h2 style={{
            fontSize: "32px",
            fontWeight: 800,
            color: "var(--text)",
            margin: 0,
            letterSpacing: "-0.5px"
          }}>
            Browse by Category
          </h2>
          <p style={{
            fontSize: "16px",
            color: "var(--text-muted)",
            margin: "12px 0 0 0",
            fontWeight: 300
          }}>
