          </p>
        </div>

        <div style={{
          backgroundColor: "var(--bg-card)",
          borderRadius: "12px",
          border: "1px solid var(--border)",
          padding: "20px 24px",
          marginBottom: 40,
          display: "flex",
          gap: 20,
          alignItems: "center",
          flexWrap: "wrap",
          boxShadow: "0 4px 12px rgba(0,0,0,0.05)"
        }}>
          <select
            value={selectedType}
            onChange={handleFilterChange}
            style={{
              padding: "10px 14px",
              fontSize: "14px",
              fontWeight: 600,
              border: "1px solid var(--border)",
              borderRadius: "8px",
              backgroundColor: "var(--bg)",
              color: "var(--text)",
              cursor: "pointer",
              transition: "all 0.2s",
              minWidth: 220,
              outline: "none"
            }}
            onFocus={(e) => {
              e.currentTarget.style.borderColor = "var(--primary)";
              e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
            }}
            onBlur={(e) => {
              e.currentTarget.style.borderColor = "var(--border)";
              e.currentTarget.style.boxShadow = "none";
            }}
          >
            <option value="all">All Vehicle Types</option>
            {types.map((t) => (
              <option key={t} value={t}>
                {t}
              </option>
            ))}
          </select>
          <div style={{
            fontSize: "14px",
            color: "var(--text)",
            fontWeight: 600,
            display: "flex",
            gap: 8,
            alignItems: "center"
          }}>
            <span style={{ color: "var(--text-muted)" }}>Showing:</span>
            <span style={{ 
              backgroundColor: "var(--primary-soft)",
              color: "var(--primary)",
              padding: "4px 10px",
              borderRadius: "6px",
              fontWeight: 700,
              letterSpacing: "0.3px"
            }}>
              {filteredVehicles.length}
            </span>
            <span style={{ color: "var(--text-muted)" }}>vehicle{filteredVehicles.length !== 1 ? "s" : ""}</span>
          </div>
        </div>

        {/* VEHICLES GRID */}
        {loading ? (
          <div style={{ textAlign: "center", padding: "80px 20px", color: "var(--text-muted)" }}>
            <div style={{ fontSize: "16px", fontWeight: 500 }}>Loading inventory...</div>
          </div>
        ) : filteredVehicles.length === 0 ? (
          <div style={{ textAlign: "center", padding: "80px 20px", color: "var(--text-muted)" }}>
            <div style={{ fontSize: "16px", fontWeight: 500 }}>No vehicles found for the selected type</div>
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
            gap: 24
          }}>
            {filteredVehicles.map((v) => (
              <VehicleCard key={v._id} vehicle={v} navigate={navigate} />
            ))}
          </div>
        )}
      </div>

      {/* CTA FOOTER */}
      <div style={{
        background: "linear-gradient(135deg, var(--primary) 0%, rgba(26, 71, 42, 0.9) 100%)",
        color: "white",
        padding: "100px 20px",
        textAlign: "center",
        marginTop: 80,
        position: "relative",
        overflow: "hidden"
      }}>
        {/* Decorative elements */}
        <div style={{
          position: "absolute",
          top: "-50%",
          right: "-15%",
          width: "600px",
          height: "600px",
          borderRadius: "50%",
          backgroundColor: "rgba(255, 255, 255, 0.05)",
          filter: "blur(40px)"
        }} />

        <div style={{ maxWidth: 700, margin: "0 auto", position: "relative", zIndex: 1 }}>
          <h2 style={{
            fontSize: "40px",
            fontWeight: 800,
            marginBottom: 20,
            letterSpacing: "-0.5px",
            textShadow: "0 2px 10px rgba(0, 0, 0, 0.2)"
          }}>
            Experience the Difference
          </h2>
          <p style={{
            fontSize: "16px",
            fontWeight: 300,
            opacity: 0.95,
            marginBottom: 40,
            lineHeight: 1.7,
            letterSpacing: "0.3px"
          }}>
            Take any vehicle for a personal test drive. Let our expert team guide you through every detail and help you find your perfect match.
          </p>
          <button 
            onClick={() => navigate("/book-appointment")}
            style={{
              backgroundColor: "white",
              color: "var(--primary)",
              fontWeight: 700,
              padding: "16px 40px",
              fontSize: "16px",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              transition: "all 0.3s ease",
              letterSpacing: "0.4px",
              boxShadow: "0 12px 32px rgba(0, 0, 0, 0.25)"
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-3px)";
              e.currentTarget.style.boxShadow = "0 16px 40px rgba(0, 0, 0, 0.35)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow = "0 12px 32px rgba(0, 0, 0, 0.25)";
            }}
          >
            Schedule Your Test Drive
          </button>
        </div>
      </div>

      <style>{`
        @media (max-width: 768px) {
          div[style*="fontSize: 56px"] {
            font-size: 36px !important;
          }
          div[style*="fontSize: 40px"] {
            font-size: 28px !important;
          }
          div[style*="gridTemplateColumns: repeat(auto-fit"] {
            grid-template-columns: 1fr !important;
          }
          div[style*="gridTemplateColumns: repeat(auto-fill"] {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
};

function StatCard({ number, label, description, icon }) {
